sub extract_specific_data {
    my ($text) = @_;
    my ($author, $date, $table_info) = ('', '', '');

    # Check for specific patterns that could indicate date or author
    if ($text =~ /Author: (.+)/i) {
        $author = $1;
    }
    if ($text =~ /Date: (.+)/i) {
        $date = $1;
    }

    # Extract table information (this is a basic example, you might need to adjust based on your needs)
    if ($text =~ /Table Information:(\n[\s\S]+?)\n/) {
        $table_info = $1;
    }

    return ($author, $date, $table_info);
}
